#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        int collisions = 0;
        int likes[M];
        for (int i = 0; i < M; i++) likes[i] = 0;
        for (int i = 0; i < N; i++) {
            char line[11];
            scanf("%s", line);
            for (int j = 0; j < M; j++) {
                if (line[j] == '1') likes[j]++;
            }
        }
        for (int i = 0; i < M; i++) {
            if (likes[i] > 1) {
                collisions += (likes[i] * (likes[i] - 1)) / 2;
            }
        }
        printf("%d\n", collisions);
    }
    return 0;
}

