code.Java:
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int M = sc.nextInt();
            int collisions = 0;
            int[] likes = new int[M];
            for (int i = 0; i < N; i++) {
                String line = sc.next();
                for (int j = 0; j < M; j++) {
                    if (line.charAt(j) == '1') likes[j]++;
                }
            }
            for (int i = 0; i < M; i++) {
                if (likes[i] > 1) {
                    collisions += (likes[i] * (likes[i] - 1)) / 2;
                }
            }
            System.out.println(collisions);
        }
    }
}

