const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [N, M] = readline().split(' ').map(Number);
    let collisions = 0;
    let likes = new Array(M).fill(0);
    for (let j = 0; j < N; j++) {
        const line = readline();
        for (let k = 0; k < M; k++) {
            if (line[k] === '1') likes[k]++;
        }
    }
    for (let j = 0; j < M; j++) {
        if (likes[j] > 1) {
            collisions += (likes[j] * (likes[j] - 1)) / 2;
        }
    }
    console.log(collisions);
}

